import type { Middleware } from "@hushkey/howl";
import type { State } from "../howl.config.ts";

export const auth: Middleware<State> = async (ctx) => {
  const token = ctx.cookies.get("token");
  if (token) {
    ctx.state.userContext = await verify(token); // available downstream
  }
  const res = await ctx.next();
  res.headers.set("X-Frame-Options", "DENY");
  return res;
};

